{"content": "<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Interstellar Black Hole - Gargantua</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }
        body {
            overflow: hidden;
            background: #000;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
        }
        canvas {
            display: block;
        }

        /* Frosted glass card */
        .info-card {
            position: fixed;
            bottom: 24px;
            left: 24px;
            padding: 20px 24px;
            background: rgba(15, 20, 30, 0.6);
            backdrop-filter: blur(16px);
            -webkit-backdrop-filter: blur(16px);
            border: 1px solid rgba(100, 150, 255, 0.2);
            border-radius: 12px;
            color: #fff;
            z-index: 100;
            min-width: 220px;
        }

        .info-card h1 {
            font-size: 22px;
            font-weight: 700;
            margin-bottom: 14px;
            background: linear-gradient(135deg, #4fc3f7, #81d4fa, #b3e5fc, #4fc3f7);
            background-size: 300% 300%;
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
            background-clip: text;
            animation: gradientShift 4s ease infinite;
        }

        @keyframes gradientShift {
            0%, 100% { background-position: 0% 50%; }
            50% { background-position: 100% 50%; }
        }

        .info-card .controls {
            font-size: 13px;
            line-height: 1.7;
            color: rgba(200, 220, 255, 0.85);
        }

        .info-card .control-item {
            display: flex;
            align-items: center;
            gap: 8px;
            margin-bottom: 4px;
        }

        .info-card .key {
            display: inline-block;
            padding: 2px 8px;
            background: rgba(100, 150, 255, 0.15);
            border: 1px solid rgba(100, 150, 255, 0.3);
            border-radius: 4px;
            font-size: 11px;
            color: rgba(180, 210, 255, 0.9);
        }

        .toggle-container {
            margin-top: 14px;
            padding-top: 12px;
            border-top: 1px solid rgba(100, 150, 255, 0.15);
            display: flex;
            align-items: center;
            gap: 10px;
        }

        .toggle-label {
            font-size: 12px;
            color: rgba(200, 220, 255, 0.85);
        }

        /* Toggle switch styling */
        .toggle-switch {
            position: relative;
            width: 40px;
            height: 20px;
        }

        .toggle-switch input {
            opacity: 0;
            width: 0;
            height: 0;
            position: absolute;
            left: 0;
            top: 0;
        }

        .toggle-slider {
            position: absolute;
            cursor: pointer;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            background-color: rgba(100, 150, 255, 0.2);
            border: 1px solid rgba(100, 150, 255, 0.4);
            border-radius: 20px;
            transition: 0.3s;
        }

        .toggle-slider:before {
            position: absolute;
            content: "";
            height: 14px;
            width: 14px;
            left: 2px;
            bottom: 2px;
            background-color: rgba(180, 210, 255, 0.8);
            border-radius: 50%;
            transition: 0.3s;
        }

        input:checked + .toggle-slider {
            background-color: rgba(79, 195, 247, 0.4);
            border-color: rgba(79, 195, 247, 0.6);
        }

        input:checked + .toggle-slider:before {
            transform: translateX(20px);
            background-color: #4fc3f7;
        }
    </style>
</head>
<body>
    <!-- Frosted glass info card -->
    <div class="info-card">
        <h1>GARGANTUA</h1>
        <div class="controls">
            <div class="control-item">
                <span class="key">Left Click</span>
                <span>Rotate view</span>
            </div>
            <div class="control-item">
                <span class="key">Right Click</span>
                <span>Pan</span>
            </div>
            <div class="control-item">
                <span class="key">Scroll</span>
                <span>Zoom</span>
            </div>
        </div>
        <div class="toggle-container">
            <label class="toggle-switch">
                <input type="checkbox" id="anim-toggle" checked>
                <span class="toggle-slider"></span>
            </label>
            <span class="toggle-label">Animation</span>
        </div>
    </div>

    <!-- Import map for Three.js modules -->
    <script type="importmap">
    {
        "imports": {
            "three": "https://cdn.jsdelivr.net/npm/three@0.160.0/build/three.module.js",
            "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.160.0/examples/jsm/"
        }
    }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // ============================================================
        // CONFIGURATION - Adjust these parameters for customization
        // ============================================================
        const CONFIG = {
            // Black hole physical parameters
            bhRadius: 1.0,                    // Event horizon radius
            diskInner: 3.0,                   // Accretion disk inner edge
            diskOuter: 10.0,                  // Accretion disk outer edge

            // Camera interaction limits
            minZoom: 1.5,                     // Minimum zoom distance
            maxZoom: 60.0,                    // Maximum zoom distance

            // Ray marching settings
            maxSteps: 150,                    // Maximum ray marching steps (150 or fewer as per requirement)

            // Visual parameters
            exposure: 1.4,                    // Tone mapping exposure (1.0-2.0)
            diskBrightness: 2.5,              // Accretion disk glow intensity
            starDensity: 80.0,                // Starfield density
            lensStrength: 2.0,                // Gravitational lensing strength
        };

        // ============================================================
        // VERTEX SHADER - Simple full-screen quad
        // ============================================================
        const vertexShader = `
            precision highp float;
            varying vec2 vUv;

            void main() {
                vUv = uv;
                // Direct NDC positioning for full-screen quad
                gl_Position = vec4(position, 1.0);
            }
        `;

        // ============================================================
        // FRAGMENT SHADER - Black hole ray marching with gravitational lensing
        // ============================================================
        const fragmentShader = `
            precision highp float;

            // Varyings
            varying vec2 vUv;

            // Core uniforms - updated every frame
            uniform float iTime;
            uniform vec2 iResolution;
            uniform vec3 iCameraPos;
            uniform vec3 iCameraDir;
            uniform vec3 iCameraUp;
            uniform float iFov;

            // Black hole configuration
            uniform float uBhRadius;          // Event horizon radius (~1.0)
            uniform float uDiskInner;         // Accretion disk inner edge (~3.0)
            uniform float uDiskOuter;         // Accretion disk outer edge (~10.0)
            uniform float uDiskBrightness;    // Disk glow intensity
            uniform float uExposure;          // Tone mapping exposure
            uniform float uStarDensity;       // Starfield density
            uniform float uLensStrength;      // Gravitational lensing strength

            #define MAX_STEPS 150              // Ray marching step limit
            #define PI 3.14159265359
            #define TWO_PI 6.28318530718

            // --------------------------------------------------------
            // HASH FUNCTIONS - For procedural starfield generation
            // --------------------------------------------------------
            float hash(vec3 p) {
                p = fract(p * 0.3183099 + 0.1);
                p *= 17.0;
                return fract(p.x * p.y * p.z * (p.x + p.y + p.z));
            }

            float hash2D(vec2 p) {
                return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453);
            }

            // --------------------------------------------------------
            // NOISE FUNCTIONS - For starfield twinkling/breathing
            // --------------------------------------------------------
            float noise(vec3 p) {
                vec3 i = floor(p);
                vec3 f = fract(p);
                f = f * f * (3.0 - 2.0 * f);

                return mix(
                    mix(mix(hash(i), hash(i + vec3(1,0,0)), f.x),
                        mix(hash(i + vec3(0,1,0)), hash(i + vec3(1,1,0)), f.x), f.y),
                    mix(mix(hash(i + vec3(0,0,1)), hash(i + vec3(1,0,1)), f.x),
                        mix(hash(i + vec3(0,1,1)), hash(i + vec3(1,1,1)), f.x), f.y), f.z
                );
            }

            // --------------------------------------------------------
            // PROCEDURAL STARFIELD - Multi-colored with breathing effect
            // --------------------------------------------------------
            vec3 starfield(vec3 dir) {
                vec3 col = vec3(0.0);

                // Breathing/pulsing effect based on time
                float breath = 0.85 + 0.15 * sin(iTime * 0.5);

                // Multiple star layers for depth
                for (float layer = 0.0; layer < 4.0; layer++) {
                    float scale = uStarDensity * (1.0 + layer * 0.5);
                    vec3 p = dir * scale;
                    vec3 fp = fract(p) - 0.5;
                    vec3 ip = floor(p);

                    float h = hash(ip + layer * 100.0);

                    // Star brightness with distance from center
                    float starSize = 0.04 + h * 0.03;
                    float d = length(fp);
                    float star = smoothstep(starSize, 0.0, d);

                    // Twinkling effect
                    float twinkle = 0.7 + 0.3 * sin(iTime * (2.0 + h * 3.0) + h * TWO_PI);
                    star *= twinkle * breath;

                    // Color based on hash - blue supergiants, red dwarfs, white stars
                    vec3 starColor;
                    if (h < 0.15) {
                        // Blue-white supergiants
                        starColor = vec3(0.7, 0.85, 1.0);
                    } else if (h < 0.3) {
                        // White stars
                        starColor = vec3(1.0, 1.0, 0.95);
                    } else if (h < 0.45) {
                        // Yellow-white
                        starColor = vec3(1.0, 0.98, 0.85);
                    } else if (h < 0.6) {
                        // Orange dwarfs
                        starColor = vec3(1.0, 0.85, 0.6);
                    } else if (h < 0.75) {
                        // Red dwarfs
                        starColor = vec3(1.0, 0.7, 0.5);
                    } else {
                        // Red giants
                        starColor = vec3(1.0, 0.5, 0.3);
                    }

                    col += star * starColor * (0.5 + 0.5 * h);
                }

                return col;
            }

            // --------------------------------------------------------
            // ACCRETION DISK - With Doppler effect (brighter left, darker right)
            // --------------------------------------------------------
            vec3 accretionDisk(vec3 pos) {
                float r = length(pos.xz);

                // Check if within disk bounds
                if (r < uDiskInner || r > uDiskOuter) return vec3(0.0);

                // Normalize radius within disk
                float t = (r - uDiskInner) / (uDiskOuter - uDiskInner);

                // Disk structure - sharper inner edge, gradual outer falloff
                float intensity = exp(-t * 1.5) * (1.0 - exp(-(1.0 - t) * 8.0));

                // Doppler effect - rotating disk (counter-clockwise from above)
                // Tangential velocity direction: (-z, 0, x) normalized
                vec3 velDir = normalize(vec3(-pos.z, 0.0, pos.x));
                // View direction from disk point to camera
                vec3 viewDir = normalize(iCameraPos - pos);
                // Doppler: dot product of velocity and view direction
                float doppler = dot(velDir, viewDir);

                // Brighter on approaching side (left from camera), darker on receding
                // Scale doppler effect - stronger near inner edge
                float dopplerScale = 0.6 + 0.4 * (1.0 - t);
                float brightnessMod = 1.0 + doppler * dopplerScale;

                // Color gradient: hot white/yellow inner, cooler orange/red outer
                vec3 innerColor = vec3(1.0, 0.95, 0.8);   // Hot white-yellow
                vec3 midColor = vec3(1.0, 0.7, 0.3);     // Orange
                vec3 outerColor = vec3(0.9, 0.3, 0.1);    // Red-orange

                vec3 diskColor;
                if (t < 0.3) {
                    diskColor = mix(innerColor, midColor, t / 0.3);
                } else {
                    diskColor = mix(midColor, outerColor, (t - 0.3) / 0.7);
                }

                // Apply Doppler brightness modulation
                diskColor *= brightnessMod;
                intensity *= uDiskBrightness;

                // Turbulence/fluctuations for realism
                float ang = atan(pos.z, pos.x);
                float turb = 0.8 + 0.2 * noise(vec3(ang * 3.0, r * 2.0, iTime * 0.3));

                return diskColor * intensity * turb;
            }

            // --------------------------------------------------------
            // PHOTON RING / GRAVITATIONAL LENSING GLOW
            // --------------------------------------------------------
            vec3 photonRing(vec3 pos, float r) {
                // Glow near the photon sphere (~1.5 * Schwarzschild radius)
                float photonRadius = uBhRadius * 1.5;
                float ringWidth = uBhRadius * 0.3;
                float ringDist = abs(r - photonRadius);

                // Exponential falloff for the ring
                float ring = exp(-ringDist * ringDist / (ringWidth * ringWidth));

                // Color: hot plasma white-blue
                vec3 ringColor = vec3(0.8, 0.9, 1.0);

                // Time-varying intensity for "breathing" effect
                float pulse = 0.9 + 0.1 * sin(iTime * 2.0 + r * 3.0);

                return ringColor * ring * pulse * 0.5;
            }

            // --------------------------------------------------------
            // RAY-PLANE INTERSECTION - For accurate disk hit detection
            // --------------------------------------------------------
            float rayPlaneIntersect(vec3 ro, vec3 rd, float planeY) {
                if (abs(rd.y) < 1e-5) return -1.0;
                float t = (planeY - ro.y) / rd.y;
                return t > 0.0 ? t : -1.0;
            }

            // --------------------------------------------------------
            // MAIN RAY MARCHING LOOP
            // --------------------------------------------------------
            vec4 rayMarch(vec3 ro, vec3 rd) {
                vec3 pos = ro;
                vec3 dir = rd;

                vec3 colorAccum = vec3(0.0);
                float alphaAccum = 0.0;
                float glowAccum = 0.0;

                bool hitDisk = false;
                bool hitHorizon = false;

                float stepSize = 0.15;  // Initial step size

                for (int i = 0; i < MAX_STEPS; i++) {
                    float r = length(pos);

                    // Check event horizon
                    if (r < uBhRadius) {
                        hitHorizon = true;
                        // Add some glow near horizon
                        glowAccum += 0.02 / (pow(r - uBhRadius, 2.0) + 0.1);
                        break;
                    }

                    // Escape condition
                    if (r > 80.0) break;

                    // Adaptive step size - smaller near disk region
                    if (r > uDiskInner - 1.0 && r < uDiskOuter + 2.0) {
                        stepSize = 0.08;
                    } else if (r > 20.0) {
                        stepSize = 0.4;
                    } else {
                        stepSize = 0.15;
                    }

                    // --------------------------------------------------------
                    // GRAVITATIONAL LENSING - Bend ray toward black hole
                    // --------------------------------------------------------
                    // Force toward center: F = -k * normalize(pos) / r^2
                    float k = uLensStrength * uBhRadius * uBhRadius;
                    vec3 force = -normalize(pos) * (k / (r * r));
                    dir = normalize(dir + force * stepSize);

                    // --------------------------------------------------------
                    // ACCRETION DISK INTERSECTION (y = 0 plane)
                    // --------------------------------------------------------
                    if (!hitDisk && abs(dir.y) > 1e-5) {
                        float tPlane = -pos.y / dir.y;
                        if (tPlane > 0.0 && tPlane <= stepSize * 1.5) {
                            vec3 diskHit = pos + dir * tPlane;
                            float diskR = length(diskHit.xz);

                            if (diskR >= uDiskInner && diskR <= uDiskOuter) {
                                // Hit the accretion disk
                                vec3 diskColor = accretionDisk(diskHit);
                                float diskAlpha = 0.9;

                                // Accumulate with depth-based fade
                                float depthFade = 1.0 - exp(-r * 0.1);
                                colorAccum += diskColor * diskAlpha * depthFade * (1.0 - alphaAccum);
                                alphaAccum += diskAlpha * (1.0 - alphaAccum) * depthFade;
                                hitDisk = true;
                            }
                        }
                    }

                    // --------------------------------------------------------
                    // PHOTON RING CONTRIBUTION - Accumulate glow near photon sphere
                    // --------------------------------------------------------
                    glowAccum += photonRing(pos, r).r * 0.015;

                    // Advance ray
                    pos += dir * stepSize;
                }

                // --------------------------------------------------------
                // FINAL COLOR COMPOSITION
                // --------------------------------------------------------
                vec3 finalColor;

                if (hitHorizon) {
                    // Black hole - but still add accumulated glow
                    finalColor = colorAccum + vec3(glowAccum * 0.5);
                } else {
                    // Escaped ray - add starfield
                    vec3 stars = starfield(dir);
                    finalColor = colorAccum + stars * (1.0 - alphaAccum);
                }

                // Add photon ring glow
                finalColor += vec3(glowAccum * 0.4, glowAccum * 0.5, glowAccum * 0.6);

                // Apply exposure and tone mapping
                finalColor *= uExposure;
                finalColor = finalColor / (1.0 + finalColor);  // Reinhard tone mapping
                finalColor = pow(finalColor, vec3(1.0 / 2.2)); // Gamma correction

                return vec4(finalColor, 1.0);
            }

            // --------------------------------------------------------
            // MAIN - Construct ray and render
            // --------------------------------------------------------
            void main() {
                // Ray construction from camera parameters (NOT using inverse matrices)
                vec2 uv = vUv * 2.0 - 1.0;

                // Prevent division by zero in aspect ratio calculation
                float aspect = max(iResolution.x, 1.0) / max(iResolution.y, 1.0);
                uv.x *= aspect;

                // Camera basis vectors
                vec3 camDir = normalize(iCameraDir);
                vec3 camRight = normalize(cross(camDir, iCameraUp));
                vec3 camUp = cross(camRight, camDir);

                // FOV to focal length (with zero protection)
                float fovRad = iFov * PI / 180.0;
                float focalLength = 1.0 / max(tan(fovRad * 0.5), 1e-4);

                // Construct ray direction
                vec3 rayDir = normalize(camRight * uv.x + camUp * uv.y + camDir * focalLength);
                vec3 rayOrigin = iCameraPos;

                // Ray march to compute final color
                gl_FragColor = rayMarch(rayOrigin, rayDir);
            }
        `;

        // ============================================================
        // THREE.JS SCENE SETUP
        // ============================================================

        // Renderer
        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
        renderer.setDrawingBufferSize(window.innerWidth, window.innerHeight);
        document.body.appendChild(renderer.domElement);

        // Scene
        const scene = new THREE.Scene();

        // Camera - Perspective camera for OrbitControls
        const camera = new THREE.PerspectiveCamera(
            60,  // FOV
            window.innerWidth / window.innerHeight,
            0.1, // Near
            1000 // Far
        );
        camera.position.set(0, 15, 30);
        camera.lookAt(0, 0, 0);

        // OrbitControls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.dampingFactor = 0.05;
        controls.minDistance = CONFIG.minZoom;
        controls.maxDistance = CONFIG.maxZoom;
        controls.enablePan = true;
        controls.target.set(0, 0, 0);

        // Shader material uniforms
        const uniforms = {
            iTime: { value: 0.0 },
            iResolution: { value: new THREE.Vector2(window.innerWidth, window.innerHeight) },
            iCameraPos: { value: camera.position.clone() },
            iCameraDir: { value: new THREE.Vector3(0, 0, -1) },
            iCameraUp: { value: camera.up.clone() },
            iFov: { value: camera.fov },
            uBhRadius: { value: CONFIG.bhRadius },
            uDiskInner: { value: CONFIG.diskInner },
            uDiskOuter: { value: CONFIG.diskOuter },
            uDiskBrightness: { value: CONFIG.diskBrightness },
            uExposure: { value: CONFIG.exposure },
            uStarDensity: { value: CONFIG.starDensity },
            uLensStrength: { value: CONFIG.lensStrength },
