    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // ============================================================
        // CONFIGURATION - Adjust these parameters for customization
        // ============================================================
        const CONFIG = {
            // Black hole physical parameters
            bhRadius: 1.0,                    // Event horizon radius
            diskInner: 3.0,                   // Accretion disk inner edge
            diskOuter: 10.0,                  // Accretion disk outer edge

            // Camera interaction limits
            minZoom: 1.5,                     // Minimum zoom distance
            maxZoom: 60.0,                    // Maximum zoom distance

            // Ray marching settings
            maxSteps: 150,                    // Maximum ray marching steps (150 or fewer as per requirement)

            // Visual parameters
            exposure: 1.4,                    // Tone mapping exposure (1.0-2.0)
            diskBrightness: 2.5,              // Accretion disk glow intensity
            starDensity: 80.0,                // Starfield density
            lensStrength: 2.0,                // Gravitational lensing strength
        };

        // ============================================================
        // VERTEX SHADER - Simple full-screen quad
        // ============================================================
        const vertexShader = `
            precision highp float;
            varying vec2 vUv;

            void main() {
                vUv = uv;
                // Direct NDC positioning for full-screen quad
                gl_Position = vec4(position, 1.0);
            }
        `;

        // ============================================================
        // FRAGMENT SHADER - Black hole ray marching with gravitational lensing
        // ============================================================
        const fragmentShader = `
            precision highp float;

            // Varyings
            varying vec2 vUv;

            // Core uniforms - updated every frame
            uniform float iTime;
            uniform vec2 iResolution;
            uniform vec3 iCameraPos;
            uniform vec3 iCameraDir;
            uniform vec3 iCameraUp;
            uniform float iFov;

            // Black hole configuration
            uniform float uBhRadius;          // Event horizon radius (~1.0)
            uniform float uDiskInner;         // Accretion disk inner edge (~3.0)
            uniform float uDiskOuter;         // Accretion disk outer edge (~10.0)
            uniform float uDiskBrightness;    // Disk glow intensity
            uniform float uExposure;          // Tone mapping exposure
            uniform float uStarDensity;       // Starfield density
            uniform float uLensStrength;      // Gravitational lensing strength

            #define MAX_STEPS 150              // Ray marching step limit
            #define PI 3.14159265359
            #define TWO_PI 6.28318530718

            // --------------------------------------------------------
            // HASH FUNCTIONS - For procedural starfield generation
            // --------------------------------------------------------
            float hash(vec3 p) {
                p = fract(p * 0.3183099 + 0.1);
                p *= 17.0;
                return fract(p.x * p.y * p.z * (p.x + p.y + p.z));
            }

            float hash2D(vec2 p) {
                return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453);
            }

            // --------------------------------------------------------
            // NOISE FUNCTIONS - For starfield twinkling/breathing
            // --------------------------------------------------------
            float noise(vec3 p) {
                vec3 i = floor(p);
                vec3 f = fract(p);
                f = f * f * (3.0 - 2.0 * f);

                return mix(
                    mix(mix(hash(i), hash(i + vec3(1,0,0)), f.x),
                        mix(hash(i + vec3(0,1,0)), hash(i + vec3(1,1,0)), f.x), f.y),
                    mix(mix(hash(i + vec3(0,0,1)), hash(i + vec3(1,0,1)), f.x),
                        mix(hash(i + vec3(0,1,1)), hash(i + vec3(1,1,1)), f.x), f.y), f.z
                );
            }

