            // PROCEDURAL STARFIELD - Multi-colored with breathing effect
            // --------------------------------------------------------
            vec3 starfield(vec3 dir) {
                vec3 col = vec3(0.0);

                // Breathing/pulsing effect based on time
                float breath = 0.85 + 0.15 * sin(iTime * 0.5);

                // Multiple star layers for depth
                for (float layer = 0.0; layer < 4.0; layer++) {
                    float scale = uStarDensity * (1.0 + layer * 0.5);
                    vec3 p = dir * scale;
                    vec3 fp = fract(p) - 0.5;
                    vec3 ip = floor(p);

                    float h = hash(ip + layer * 100.0);

